class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: GetEnvironmentVariable now returns null for
        // empty env vars on Unix. Use string.IsNullOrEmpty to preserve old behavior,
        // or check existence separately with Environment.GetEnvironmentVariables().
        var envVars = Environment.GetEnvironmentVariables();
        if (!envVars.Contains("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

